def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            if cap == 0:
                priorities[i] = np.inf
            else:
                priorities[i] = np.nan
            continue
        ratio = item / cap
        score = 0.0
        decay_factor = 1.0
        bonus_factor = 1.0
        for j in range(1, 15):
            if j % 3 == 0 and j % 5 == 0:
                decay_factor *= 0.95
            elif j % 3 == 0:
                decay_factor *= 1.12
            elif j % 5 == 0:
                decay_factor *= 0.88
            modifier = np.sin(ratio * j * np.pi) + np.cos(cap % (j + 1))
            if ratio < 0.1 * j:
                score += ((j ** 2) / (j + 1)) * np.exp(-ratio * j) * decay_factor * modifier
            else:
                score += (np.log1p(j) * (ratio ** 1.7) + np.tanh(cap / (j + 2))) * decay_factor / (j + 1) * modifier
            if (cap + j) % 4 == 0:
                score *= 1.05
            elif (cap * j + item) % 7 == 0:
                score *= 0.94
            if j == 10:
                for k in range(1, 6):
                    diff = cap - item * k
                    if diff > 0:
                        if diff % 3 == 0:
                            score += np.cbrt(diff) / (k + 3) * bonus_factor
                        else:
                            score -= np.log1p(abs(diff)) / (k + 2) * bonus_factor
                    else:
                        score -= ((abs(diff)) ** 1.3) / (k + 4) * bonus_factor
            if j % 7 == 0:
                bonus_factor *= 1.02
        if score == 0:
            priorities[i] = np.inf
        elif score < 0:
            priorities[i] = -score * np.log1p(cap + item) * 1.1
        else:
            if cap > item * 3:
                priorities[i] = -score / (np.sqrt(cap) + 0.5)
            else:
                priorities[i] = -score / (cap + 1.5)
        if ratio > 0.85:
            priorities[i] *= 1.25
        elif ratio < 0.05:
            priorities[i] *= 0.75
        else:
            if (cap + item) % 2 == 0:
                priorities[i] *= 1.1
            else:
                priorities[i] *= 0.9
        if np.isclose(priorities[i], 0, atol=1e-9):
            priorities[i] = np.inf
    return priorities
